import java.util.Arrays;
import java.util.Random;

public class MatrixMultiplication {

    private static int[][] matrixA;
    private static int[][] matrixB;
    private static int[][] result;
    private static int currentRow = 0;
    private static final Object lock = new Object();

    public static void main(String[] args) {
        int rowsA = 3, colsA = 3;
        int rowsB = 3, colsB = 3;
        matrixA = generateMatrix(rowsA, colsA);
        matrixB = generateMatrix(rowsB, colsB);
        result = new int[rowsA][colsB];

        int numThreads = 4;
        Thread[] threads = new Thread[numThreads];
        for (int i = 0; i < numThreads; i++) {
            threads[i] = new Thread(new MultiplyTask());
            threads[i].start();
        }

        for (Thread t : threads) {
            try {
                t.join();
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        }

        printMatrix(matrixA, "A");
        printMatrix(matrixB, "B");
        printMatrix(result, "Result");
    }

    private static class MultiplyTask implements Runnable {
        @Override
        public void run() {
            int row;
            while (true) {
                synchronized (lock) {
                    if (currentRow >= result.length) break;
                    row = currentRow;
                    currentRow++;
                }
                for (int j = 0; j < matrixB[0].length; j++) {
                    for (int k = 0; k < matrixA[0].length; k++) {
                        result[row][j] += matrixA[row][k] * matrixB[k][j];
                    }
                }
            }
        }
    }

    private static int[][] generateMatrix(int rows, int cols) {
        int[][] matrix = new int[rows][cols];
        Random rand = new Random();
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                matrix[i][j] = rand.nextInt(10);
            }
        }
        return matrix;
    }

    private static void printMatrix(int[][] matrix, String name) {
        System.out.println("Matrix " + name + ":");
        for (int[] row : matrix) {
            System.out.println(Arrays.toString(row));
        }
    }
}
