    if (!file.is_open()) {
        std::cerr << "Error: Could not open file " << argv[1] << '\n';
        return 1;
    }

    double total = 0.0;
    std::string line;

    while (std::getline(file, line)) {
        std::istringstream iss(line);
        std::vector<std::string> tokens;
        std::string token;

        while (iss >> token)
            tokens.push_back(token);

        if (tokens.size() < 2) {
            std::cerr << "Error: Invalid line format: " << line << '\n';
            continue;
        }

        std::string priceStr = tokens.back();
        tokens.pop_back();
        std::istringstream pss(priceStr);
        double price;
        if (!(pss >> price)) {
            std::cerr << "Error: Invalid price in line: " << line << '\n';
            continue;
        }

        char remaining;
        if (pss >> remaining) {
            std::cerr << "Error: Invalid price in line: " << line << '\n';
            continue;
        }

        total += price;
    }

    std::cout << "Total cost: " << total << '\n';
    return 0;
