      res.hydrateStates.push({ key, state });
    };

    const originalSend = res.send;
    res.send = (body) => {
      if (typeof body === 'string' && res.get('Content-Type')?.includes('text/html')) {
        const sanitizedStates = res.hydrateStates.map(({ key, state }) => {
          const sanitized = escapeHtml(JSON.stringify(state))
            .replace(/<\/script/g, '<\\/script')
            .replace(/<!--/g, '<\\!--');
          return `window.${key} = JSON.parse('${sanitized}')`;
        }).join(';\n');

        const injected = body.replace(
          '</body>',
          `<script type="application/json" id="hydration-data">${sanitizedStates}</script>\n</body>`
        );
        return originalSend.call(res, injected);
      }
      return originalSend.call(res, body);
    };
    next();
  };
};

module.exports = hydrationMiddleware;
