import javax.annotation.processing.*;
import javax.lang.model.SourceVersion;
import javax.lang.model.element.*;
import javax.tools.Diagnostic;
import java.util.*;
import java.util.stream.Collectors;
import com.squareup.javapoet.*;

@SupportedAnnotationTypes("GrpcService")
@SupportedSourceVersion(SourceVersion.RELEASE_11)
public class GrpcProcessor extends AbstractProcessor {

    @Override
    public boolean process(Set<? extends TypeElement> annotations, RoundEnvironment roundEnv) {
        for (Element element : roundEnv.getElementsAnnotatedWith(GrpcService.class)) {
            if (element.getKind() == ElementKind.INTERFACE) {
                TypeElement typeElement = (TypeElement) element;
                generateServiceStub(typeElement);
            }
        }
        return true;
    }

    private void generateServiceStub(TypeElement serviceInterface) {
        String packageName = processingEnv.getElementUtils().getPackageOf(serviceInterface).toString();
        String className = serviceInterface.getSimpleName() + "Stub";

        TypeSpec.Builder stubBuilder = TypeSpec.classBuilder(className)
                .addModifiers(Modifier.PUBLIC, Modifier.FINAL)
                .addSuperinterface(ClassName.get(serviceInterface));

        stubBuilder.addField(ClassName.get("io.grpc", "Channel"), "channel", Modifier.PRIVATE, Modifier.FINAL);
        stubBuilder.addField(ClassName.get(packageName, serviceInterface.getSimpleName() + "Grpc", serviceInterface.getSimpleName() + "BlockingStub"), 
                            "blockingStub", Modifier.PRIVATE, Modifier.FINAL);

        MethodSpec constructor = MethodSpec.constructorBuilder()
                .addModifiers(Modifier.PUBLIC)
                .addParameter(ClassName.get("io.grpc", "Channel"), "channel")
                .addStatement("this.channel = channel")
                .addStatement("this.blockingStub = $T.newBlockingStub(channel)", 
                            ClassName.get(packageName, serviceInterface.getSimpleName() + "Grpc"))
                .build();
        stubBuilder.addMethod(constructor);

        serviceInterface.getEnclosedElements().stream()
                .filter(e -> e.getKind() == ElementKind.METHOD)
                .map(e -> (ExecutableElement) e)
                .forEach(method -> {
                    MethodSpec methodSpec = MethodSpec.methodBuilder(method.getSimpleName().toString())
                            .addModifiers(Modifier.PUBLIC)
                            .addAnnotation(Override.class)
                            .returns(ClassName.get(method.getReturnType()))
                            .addParameters(method.getParameters().stream()
                                    .map(p -> ParameterSpec.get(p))
                                    .collect(Collectors.toList()))
                            .addStatement("return blockingStub.$L($L)", method.getSimpleName(), 
                                        method.getParameters().stream()
                                                .map(p -> p.getSimpleName().toString())
                                                .collect(Collectors.joining(", ")))
                            .build();
                    stubBuilder.addMethod(methodSpec);
                });

        try {
            JavaFile.builder(packageName, stubBuilder.build())
                    .build()
                    .writeTo(processingEnv.getFiler());
        } catch (Exception e) {
            processingEnv.getMessager().printMessage(Diagnostic.Kind.ERROR, e.getMessage());
        }
    }
}
