import org.springframework.context.annotation.Bean;
import org.springframework.messaging.Message;
import org.springframework.messaging.support.MessageBuilder;
import java.util.Map;
import java.util.function.Function;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.core.type.TypeReference;

@SpringBootApplication
public class PseudonymizationFunction {

    private final ObjectMapper objectMapper = new ObjectMapper();
    private final PseudonymizationService pseudonymizationService = new PseudonymizationService();

    public static void main(String[] args) {
        SpringApplication.run(PseudonymizationFunction.class, args);
    }

    @Bean
    public Function<Message<String>, Message<String>> process() {
        return input -> {
            try {
                Map<String, Object> payload = objectMapper.readValue(input.getPayload(), new TypeReference<Map<String, Object>>() {});
                payload.replaceAll((k, v) -> pseudonymizationService.pseudonymizeField(k, v.toString()));
                String output = objectMapper.writeValueAsString(payload);
                return MessageBuilder.withPayload(output).copyHeaders(input.getHeaders()).build();
            } catch (Exception e) {
                throw new RuntimeException("Pseudonymization failed", e);
            }
        };
    }

    private static class PseudonymizationService {
        public String pseudonymizeField(String key, String value) {
            if (key.matches("email|phone|ssn|userId")) {
                return "pseudonymized-" + value.hashCode();
            }
            return value;
        }
    }
