from jax import jit, vmap

def init_model(input_dim, hidden_dim, output_dim):
    key = jax.random.PRNGKey(0)
    W1 = jax.random.normal(key, (hidden_dim, input_dim))
    b1 = jax.random.normal(key, (hidden_dim,))
    W2 = jax.random.normal(key, (output_dim, hidden_dim))
    b2 = jax.random.normal(key, (output_dim,))
    return [(W1, b1), (W2, b2)]

def apply_model(params, x):
    for i, (W, b) in enumerate(params):
        x = jnp.dot(x, W.T) + b
        if i != len(params) - 1:
            x = jax.nn.relu(x)
    return x

def pad_batch(batch):
    max_len = max(x.shape[0] for x in batch)
    return jnp.array([jnp.pad(x, (0, max_len - x.shape[0])) for x in batch])

batched_apply = vmap(apply_model, in_axes=(None, 0))

@jit
def batched_inference(params, batch):
    return batched_apply(params, batch)

def map_inference(params, batch):
    padded_batch = pad_batch(batch)
    return batched_inference(params, padded_batch)
